function(config){
  config = config || {};
  var pageUrl = (config.page && config.page.url) || (typeof location !== 'undefined' ? location.href : '');
  function txt(el){return (el && (el.innerText||el.textContent)||'').replace(/\s+/g,' ').trim();}
  function absUrl(href){
    href = (href||'').trim();
    if(!href) return '';
    if(/^javascript:/i.test(href)) return '';
    if(href.startsWith('//')) return 'https:' + href;
    try{ return new URL(href, pageUrl).href; }catch(e){ return href; }
  }
  function isBadLink(a){
    if(!a) return true;
    var href = (a.getAttribute('href')||'').trim();
    if(!href || /^javascript:/i.test(href)) return true;
    var rel = (a.getAttribute('rel')||'').toLowerCase();
    if(rel.includes('nofollow') && href.startsWith('sinaweibo://')) return true;
    var t = (a.getAttribute('title')||'') + ' ' + txt(a);
    t = t.toLowerCase();
    if(/登录|注册|隐私|条款|协议|帮助|反馈|客服|举报|广告|推广|推荐|关于|下载|app|客户端/.test(t)) return true;
    return false;
  }
  function inExcludedArea(el){
    if(!el || !el.closest) return false;
    return !!el.closest('header,nav,footer,aside,.sidebar,.side,.right,.right-rail,.m-main-nav,.Nav_wrap_gHB1a,#searchapps');
  }
  function getTargetRoot(){
    var t = config.target || {};
    var root = null;
    if(t && t.by === 'selector' && t.selector){
      root = document.querySelector(t.selector);
    } else if(t && t.by === 'query' && t.query){
      root = document.querySelector(t.query);
    } else if(t && t.query){
      root = document.querySelector(t.query);
    } else if(t && t.selector){
      root = document.querySelector(t.selector);
    }
    if(root) return root;
    return document.querySelector('#pl_feedlist_index') || document.querySelector('#pl_feed_main') || document.querySelector('.m-main') || document.body;
  }
  function pickItems(items){
    var t = config.target || {};
    var pick = t.pick;
    if(pick === undefined || pick === null) return items;
    if(typeof pick === 'number'){
      var idx = pick;
      if(idx === -1) return items.length ? [items[items.length-1]] : [];
      if(idx > 0) return items[idx-1] ? [items[idx-1]] : [];
      if(idx === 0) return items[0] ? [items[0]] : [];
      return [];
    }
    if(typeof pick === 'string'){
      var s = pick.trim();
      if(!s) return items;
      var low = s.toLowerCase();
      var filtered = items.filter(function(it){
        var hay = ((it.title||'')+' '+(it.summary||'')+' '+(it.text||'')+' '+(it.url||'')).toLowerCase();
        return hay.includes(low);
      });
      return filtered.length ? filtered : items;
    }
    return items;
  }
  function applyQueryFilter(items){
    var q = (config.query || config.searchQuery || (config.target && config.target.query) || '').toString().trim();
    if(!q) return items;
    var ql = q.toLowerCase();
    var kept = items.filter(function(it){
      var hay = ((it.title||'')+' '+(it.summary||'')+' '+(it.text||'')).toLowerCase();
      return hay.includes(ql);
    });
    return kept.length ? kept : items;
  }
  function extractFromContainer(root){
    if(!root) return {items:[], nextCursor:null};
    var candidates = [];
    var direct = root.querySelectorAll('[action-type="feed_list_item"], .card-wrap[action-type], .card-wrap');
    for(var i=0;i<direct.length;i++){
      var el = direct[i];
      if(inExcludedArea(el)) continue;
      if(el.getAttribute('action-type')==='feed_list_item' || el.hasAttribute('mid') || el.querySelector('.card-feed')) candidates.push(el);
    }
    if(candidates.length<1){
      var alt = root.querySelectorAll('.card-feed');
      for(var j=0;j<alt.length;j++){
        var p = alt[j].closest('.card-wrap') || alt[j];
        if(p && !inExcludedArea(p)) candidates.push(p);
      }
    }
    var items = [];
    for(var k=0;k<candidates.length && items.length<50;k++){
      var card = candidates[k];
      if(!card || inExcludedArea(card)) continue;
      var content = card.querySelector('.content') || card;
      var titleEl = card.querySelector('a.name') || card.querySelector('.info a.name') || card.querySelector('.card-top .title a') || card.querySelector('h3,h4,.title');
      var title = txt(titleEl);
      var summaryEl = card.querySelector('p.txt,[node-type="feed_list_content"],.txt') || card.querySelector('.content');
      var summary = txt(summaryEl);
      summary = summary.replace(/展开\s*[a-z]?$/i,'').trim();
      var url = '';
      var fromA = card.querySelector('.from a[href]');
      if(fromA && !isBadLink(fromA)) url = absUrl(fromA.getAttribute('href'));
      if(!url){
        var aList = card.querySelectorAll('a[href]');
        for(var m=0;m<aList.length;m++){
          var a = aList[m];
          if(isBadLink(a)) continue;
          if(inExcludedArea(a)) continue;
          var href = a.getAttribute('href')||'';
          if(/weibo\.com\//i.test(href) && /\/[A-Za-z0-9]{6,}/.test(href)) { url = absUrl(href); break; }
        }
      }
      if(!url){
        var mid = card.getAttribute('mid') || (card.querySelector('[mid]') && card.querySelector('[mid]').getAttribute('mid'));
        if(mid) url = absUrl('https://weibo.com/' + mid);
      }
      if(!title){
        var name = card.querySelector('a[name],a.nick-name,a[title]');
        title = txt(name) || (summary ? summary.slice(0,40) : '');
      }
      if(!summary) summary = '';
      var item = {url:url||'', title:title||'', summary:summary||''};
      item.text = item.summary || item.title || '';
      items.push(item);
    }
    var nextCursor = null;
    var pager = root.querySelector('.m-page, .W_pages, .woo-box-flex .m-page') || document.querySelector('.m-page, .W_pages');
    if(pager){
      var nextA = pager.querySelector('a.next, a[rel="next"], a[href*="page="]');
      if(nextA && !isBadLink(nextA)){
        var nu = absUrl(nextA.getAttribute('href'));
        if(nu && nu !== pageUrl) nextCursor = nu;
      }
    }
    if(!nextCursor){
      var a2 = document.querySelector('a.next[href], a[rel="next"][href]');
      if(a2 && !inExcludedArea(a2) && !isBadLink(a2)){
        var nu2 = absUrl(a2.getAttribute('href'));
        if(nu2 && nu2 !== pageUrl) nextCursor = nu2;
      }
    }
    return {items:items, nextCursor:nextCursor};
  }
  function ensureFields(items){
    return (items||[]).map(function(it){
      it = it || {};
      var o = {url:(it.url||'')+'', title:(it.title||'')+'', summary:(it.summary||'')+''};
      o.text = (it.text||o.summary||o.title||'')+'';
      return o;
    });
  }
  var root = getTargetRoot();
  var res = extractFromContainer(root);
  var items = ensureFields(res.items);
  if(items.length < (config.minItems||1)){
    var root2 = document.querySelector('#pl_feedlist_index') || document.querySelector('#pl_feed_main') || document.querySelector('.main-full') || document.querySelector('.m-main') || document.body;
    res = extractFromContainer(root2);
    items = ensureFields(res.items);
  }
  items = applyQueryFilter(items);
  items = pickItems(items);
  var requireFields = config.requireFields || config.fields || [];
  if(Array.isArray(requireFields) && requireFields.length){
    items = items.filter(function(it){
      for(var i=0;i<requireFields.length;i++){
        var f = requireFields[i];
        if(typeof f !== 'string') continue;
        if((it[f]||'').toString().trim()==='') return false;
      }
      return true;
    });
  }
  if(config.filter && typeof config.filter === 'function'){
    try{ items = items.filter(config.filter); }catch(e){}
  }
  if(config.sort && typeof config.sort === 'function'){
    try{ items = items.slice().sort(config.sort); }catch(e){}
  }
  if(items.length>50) items = items.slice(0,50);
  var nextCursor = res.nextCursor;
  if(nextCursor===undefined) nextCursor = null;
  if(nextCursor!==null) nextCursor = (nextCursor||'')+'';
  if(!nextCursor) nextCursor = null;
  return {action:'list', items:items, nextCursor:nextCursor, pageUrl:pageUrl};
}
